async def dispatch_tool(runtime, name: str, args: dict[str, Any]) -> str:
    """Execute a tool by name and return result string."""

    if name == "mara_connect":
        return await _handle_connect(runtime, args)

    if name == "mara_disconnect":
        return await _handle_disconnect(runtime, args)

    if name == "mara_get_state":
        return await _handle_get_state(runtime, args)

    if name == "mara_get_freshness":
        return await _handle_get_freshness(runtime, args)

    if name == "mara_get_events":
        return await _handle_get_events(runtime, args)

    if name == "mara_get_command_stats":
        return await _handle_get_command_stats(runtime, args)

    if name == "mara_robot_describe":
        return await _handle_robot_describe(runtime, args)

    if name == "mara_robot_state":
        return await _handle_robot_state(runtime, args)

    if name == "mara_robot_pose":
        return await _handle_robot_pose(runtime, args)

    if name == "mara_record_start":
        return await _handle_record_start(runtime, args)

    if name == "mara_record_stop":
        return await _handle_record_stop(runtime, args)

    if name == "mara_record_list":
        return await _handle_record_list(runtime, args)

    if name == "mara_record_status":
        return await _handle_record_status(runtime, args)

    if name == "mara_firmware_test":
        return await _handle_firmware_test(runtime, args)

    if name == "mara_robot_test_connection":
        return await _handle_robot_test_connection(runtime, args)

    if name == "mara_robot_test_latency":
        return await _handle_robot_test_latency(runtime, args)

    if name == "mara_robot_test_all":
        return await _handle_robot_test_all(runtime, args)

    if name == "mara_host_test":
        return await _handle_host_test(runtime, args)

    if name == "mara_arm":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.arm()
        runtime.sync_state_result(result)
        runtime.record_command("arm", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Armed".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_disarm":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.disarm()
        runtime.sync_state_result(result)
        runtime.record_command("disarm", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Disarmed".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_stop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.stop()
        runtime.sync_state_result(result)
        runtime.record_command("stop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Stopped".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_estop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.estop()
        runtime.sync_state_result(result)
        runtime.record_command("estop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "E-STOP activated".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_clear_estop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.clear_estop()
        runtime.sync_state_result(result)
        runtime.record_command("clear_estop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "E-STOP cleared".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_activate":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.activate()
        runtime.sync_state_result(result)
        runtime.record_command("activate", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Activated".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_deactivate":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.deactivate()
        runtime.sync_state_result(result)
        runtime.record_command("deactivate", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Deactivated".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_get_robot_state":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.get_state()
        runtime.sync_state_result(result)
        runtime.record_command("get_robot_state", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "get_robot_state OK"
        return f"FAIL: {result.error}"

    if name == "mara_set_velocity":
        await runtime.ensure_armed()
